// ── Screen 5: Reflection ───────────────────────────────────────
function ReflectionScreen({ scores, civInterests, scale, onFinish }) {
  const topSelf = Object.entries(scores).sort((a, b) => b[1] - a[1])[0]
  const bottomSelf = Object.entries(scores).sort((a, b) => a[1] - b[1])[0]
  const topCiv = Object.entries(civInterests).sort((a, b) => b[1] - a[1])[0]

  const topSelfDomain = SELF_DOMAINS.find(d => d.key === bottomSelf?.[0])
  const topCivDomain = CIV_DOMAINS.find(d => d.key === topCiv?.[0])
  const scaleLabel = SCALE_OPTIONS.find(o => o.key === scale)?.label?.toLowerCase() || 'the world'

  const seeds = [
    { icon: '◉', label: 'Mission Control', sub: 'your wheel is lit and waiting' },
    { icon: '☼', label: 'Daily',           sub: topSelfDomain ? `tuned to ${topSelfDomain.name}` : 'ready for you' },
    { icon: '✓', label: 'Tasks',           sub: 'first steps ready' },
    topCivDomain && { icon: '✦', label: 'The Atlas',  sub: `people working on ${topCivDomain.name.toLowerCase()}` },
    { icon: '↗', label: 'NextU',           sub: 'ready when you want to go deep' },
  ].filter(Boolean)

  let mirror = ''
  if (bottomSelf && topSelfDomain) {
    mirror += `You're carrying something in ${topSelfDomain.name} right now. `
  }
  if (topCivDomain) {
    mirror += `Out in the world, ${topCivDomain.name.toLowerCase()} is where your energy wants to go. `
  }
  mirror += `At the scale of ${scaleLabel}. That's a clear place to begin, and it's the same work at two scales.`

  return (
    <>
      <div style={{ ...s.screen, paddingTop: 20 }}>
        <p style={s.eyebrow}>Here's what I'm hearing</p>
        <p style={{ fontFamily: SERIF, fontSize: 22, lineHeight: 1.5, margin: '0 0 28px', color: INK }}>{mirror}</p>

        <div style={{ marginBottom: 28 }}>
          <p style={{ fontFamily: SC, fontSize: 13, letterSpacing: '0.16em', color: 'rgba(15,21,35,0.55)', textTransform: 'uppercase', margin: '0 0 10px' }}>Your platform is ready</p>
          {seeds.map((seed, i) => (
            <div key={seed.label} style={{ display: 'flex', alignItems: 'center', gap: 12, padding: '11px 0', borderTop: '1px solid rgba(15,21,35,0.08)', opacity: 0, animation: `seedin 0.5s ${i * 0.12}s forwards` }}>
              <div style={{ width: 28, height: 28, borderRadius: 7, background: 'rgba(200,146,42,0.1)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 14, flexShrink: 0 }}>{seed.icon}</div>
              <div>
                <span style={{ fontFamily: LORA, fontSize: 14, fontWeight: 500, color: INK }}>{seed.label}</span>
                <span style={{ fontFamily: LORA, fontSize: 13, color: 'rgba(15,21,35,0.5)' }}> — {seed.sub}</span>
              </div>
            </div>
          ))}
        </div>

        <div style={{ background: 'rgba(168,114,26,0.06)', border: '1px solid rgba(200,146,42,0.2)', borderRadius: 10, padding: '12px 16px', marginBottom: 24 }}>
          <p style={{ fontFamily: LORA, fontSize: 13, color: 'rgba(15,21,35,0.55)', margin: 0, lineHeight: 1.5 }}>
            <span style={{ color: GC, fontWeight: 500 }}>* Provisional scores</span> — these are your starting point, not your ceiling. Begin NextU for your full map.
          </p>
        </div>

        <div style={{ height: 20 }} />
      </div>
      <div style={s.foot}>
        <button style={{ ...s.btn, flex: 1 }} onClick={onFinish}>Step into NextUs</button>
      </div>

      <style>{`@keyframes seedin { to { opacity: 1 } }`}</style>
    </>
  )
}

// ── Main component ─────────────────────────────────────────────
const LOGO_B64 = ''
const TOTAL_STEPS = 5

export default function FirstLight() {
  const { user } = useAuth()
  const navigate = useNavigate()

  const [step, setStep]               = useState(0)
  const [scores, setScores]           = useState({ path: 5, spark: 5, body: 5, finances: 5, connection: 5, inner_game: 5, signal: 5 })
  const [cards, setCards]             = useState({})
  const [civInterests, setCivInterests] = useState({})
  const [scale, setScale]             = useState(null)
  const [saving, setSaving]           = useState(false)

  async function handleFinish() {
    if (!user) return
    setSaving(true)
    try {
      const reflection = document.querySelector('[data-mirror]')?.textContent || ''
      await supabase.from('users').update({
        first_light_completed_at: new Date().toISOString(),
        welcome_scores:       scores,
        welcome_challenges:   cards,
        welcome_civ_interests: civInterests,
        welcome_scale:        scale,
        welcome_reflection:   reflection,
      }).eq('id', user.id)
    } catch (e) {
      console.error('First Light save error:', e)
    } finally {
      setSaving(false)
      navigate('/', { replace: true })
    }
  }

  const next = () => setStep(s => Math.min(s + 1, TOTAL_STEPS))
  const back = () => setStep(s => Math.max(s - 1, 0))

  return (
    <div style={{ height: '100vh', background: BG, overscrollBehavior: 'none' }}>
      <div style={s.app}>
        {step > 0 && step < TOTAL_STEPS && <Progress step={step - 1} total={4} />}

        {step === 0 && <CoverScreen onBegin={next} logoB64={LOGO_B64} />}
        {step === 1 && <PersonalScreen scores={scores} setScores={setScores} cards={cards} setCards={setCards} onNext={next} onBack={back} />}
        {step === 2 && <ZoomScreen scores={scores} onNext={next} />}
        {step === 3 && <PlanetScreen civInterests={civInterests} setCivInterests={setCivInterests} onNext={next} onBack={back} />}
        {step === 4 && <ScaleScreen scale={scale} setScale={setScale} onNext={next} onBack={back} />}
        {step === 5 && <ReflectionScreen scores={scores} civInterests={civInterests} scale={scale} onFinish={handleFinish} />}
      </div>
    </div>
  )
}
